mapper.select:
SELECT p.PRODUCT_NO, p.PRODUCT_NAME, p.STORAGE_TYPE, st.DETAIL_CODE_NAME AS STORAGE_TYPE_NAME, p.PROCESS_TYPE, pt.DETAIL_CODE_NAME AS PROCESS_TYPE_NAME, p.DIVISION_TYPE, dt.DETAIL_CODE_NAME AS DIVISION_TYPE_NAME, p.UNIT_TYPE, ut.DETAIL_CODE_NAME AS UNIT_TYPE_NAME, p.SALE_TYPE, slt.DETAIL_CODE_NAME AS SALE_TYPE_NAME, p.SELLER_ID, m.COMPANY_NAME AS SELLER_NAME, p.COST_PRICE, p.VAT_AMOUNT, p.AUTO_VAT_YN, p.SALE_PRICE, p.SALE_STATUS, ss.DETAIL_CODE_NAME AS SALE_STATUS_NAME, p.DISPLAY_YN, p.SALE_START_DATE, p.SALE_END_DATE, p.REG_DT, p.MOD_DT FROM TB_BUNDLE_PRODUCT p LEFT JOIN TB_MEMBER m ON p.SELLER_ID = m.MEMBER_NO LEFT JOIN TB_DETAIL_CODE st ON p.STORAGE_TYPE = st.DETAIL_CODE AND st.GROUP_CODE = '001' AND st.CODE = '001001' LEFT JOIN TB_DETAIL_CODE pt ON p.PROCESS_TYPE = pt.DETAIL_CODE AND pt.GROUP_CODE = '001' AND pt.CODE = '001003' LEFT JOIN TB_DETAIL_CODE dt ON p.DIVISION_TYPE = dt.DETAIL_CODE AND dt.GROUP_CODE = '001' AND dt.CODE = '001002' LEFT JOIN TB_DETAIL_CODE ut ON p.UNIT_TYPE = ut.DETAIL_CODE AND ut.GROUP_CODE = '001' AND ut.CODE = '001004' LEFT JOIN TB_DETAIL_CODE slt ON p.SALE_TYPE = slt.DETAIL_CODE AND slt.GROUP_CODE = '007' AND slt.CODE = '007002' LEFT JOIN TB_DETAIL_CODE ss ON p.SALE_STATUS = ss.DETAIL_CODE AND ss.GROUP_CODE = '007' AND ss.CODE = '007001'
ORDER BY p.REG_DT DESC
LIMIT #{recordCountPerPage} OFFSET #{firstIndex}
